mapper.select:
SELECT d.document_id, d.original_file_name, d.display_name, d.extension, d.object_key, d.blob_provider FROM document d JOIN knowledge_base_document kbd ON d.document_id = kbd.document_id WHERE kbd.knowledge_base_id = #{knowledgeBaseId}
AND d.display_name LIKE CONCAT('%', #{keyword}, '%')
ORDER BY kbd.created_at DESC
